class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        n = len(s)
        max_len = 0
        for mask in range(1 << n):
            subseq = ''
            for i in range(n):
                if (mask & (1 << i)):
                    subseq += s[i]
            if subseq and int(subseq, 2) <= k:
                max_len = max(max_len, len(subseq))
        return max_len
